import (
	"database/sql"
	"errors"
	"strings"
)

type Product struct {
	ID    int
	Name  string
	Price float64
}

// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	// Normalize and validate sort direction
	sortDir = strings.ToUpper(strings.TrimSpace(sortDir))
	if sortDir != "ASC" && sortDir != "DESC" {
		return nil, errors.New("invalid sort direction: must be ASC or DESC")
	}

	// Normalize and validate order by column against allowed whitelist to prevent SQL injection
	orderBy = strings.TrimSpace(strings.ToLower(orderBy))
	allowedOrderColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}
	if !allowedOrderColumns[orderBy] {
		return nil, errors.New("invalid order by column: must be one of id, name, price")
	}

	// Construct query with fully validated inputs
	query := "SELECT id, name, price FROM products ORDER BY " + orderBy + " " + sortDir

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

